INSERT INTO public.photos VALUES (21141, 'Construcci├│n puente de Hierro 1894', 'Construcci├│n del puente del Pilar o de Hierro de Zaragoza, en 1894.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65538400, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF2C29779FE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871889038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871889038.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871889038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21928, 'Vista a├®rea Coso Bajo a├▒os 40', 'Archivo Municipal. 1927 (dataci├│n improbable que aparece en la ficha t├®cnica del Archivo). Un vuelo a motor captura desde el Barrio de Jes├║s el cuadrante al este del decumano maximo romano, desde el nov├¡simo S. Vicente de Pa├║l (a la derecha) apenas comenzado a construir los nuevos edificios que lo delimitar├ín, hasta m├ís all├í del Huerva (a la izquierda). Inmediatamente, el Ebro, el Puente de Hierro, el Paseo del Ebro (actual Echegaray y Caballero), la Plaza Tener├¡as con el enorme Dep├│sito de Autom├│viles del Ej├®rcito, y el final del Coso Bajo, donde destaca la mole de la Universidad Literaria de la Magdalena, tal y como luc├¡a desde la profunda reforma de 1846. A su izquierda, parte del antiguo Barrio de la Seo (barrio del siglo XII y construcciones de los siglos XVI-XVIII), con un cat├ílogo de viales muy remozado por la impostaci├│n de S. Vicente de Pa├║l, afectando total o parcialmente al Postigo al Ebro, calleja del Conde Alperche, callizo de La Rosa, calle del Garro, callizo del Retiro, calle del Silencio, calle Palafox, callizo de Don Mor├¡n, placeta de Li├▒├ín, calle Juan de Arag├│n, placeta de Segovia, plaza de Clariana, plaza del Reino.... Junto al Huerva, a la izquierda, el campo de f├║tbol de la Torre de Bruil, o de la calle Asalto, activo desde 1924 y con capacidad para 6000 aficionados, donde jugaba el "Zaragoza F.C." Muy cerca, la f├íbrica de regaliz ZARA, y el "Corral de Abastos de Intendencia" (actual parque "Corral de la le├▒a"). El Puente de S. Jos├® abre la Pza. de San Miguel (visible arriba del todo) hacia Miguel Servet y el Camino del Bajo Arag├│n. Ya al otro lado del Huerva, la enorme superficie de los lavaderos (y tendederos) "de la Puerta del Duque". Inmediata, la harinera del Pilar. Finalmente, visual de la enorme estructura de la Tercera Comandancia de Intendencia del Ej├®rcito, sito sobre las ruinas del anterior Convento de San Jos├®, que hasta comienzos del siglo XX fue Penal de convictos que redim├¡an sus penas cosiendo trajes. Incluido en la setentera "Op', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65528600, -0.87298300, '0101000020E6100000D3D85E0B7AEFEBBF69C36169E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14873165933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14873165933.webp', 'https://www.flickr.com/photos/zaragozaantigua/14873165933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
