INSERT INTO public.photos VALUES (25817, 'Calle Miguel de Ara 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ara, (Miguel)." Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle Basilio Boggiero hasta la calle de San Pablo, al fondo, con la iglesia de San Pablo iluminada por el sol.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65533400, -0.88605100, '0101000020E6100000AFD172A0875AECBF7BFA08FCE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886485159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886485159.webp', 'https://www.flickr.com/photos/zaragozaantigua/14886485159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23903, 'XIX Centenario 1940', 'Sello conmemorativo publicado y circulado con motivo de la celebraci├│n oficial del "XIX Centenario de la Virgen del Pilar", con un dibujo centrado en el moderno aspecto del templo del Pilar tras el puente de Piedra y el r├¡o Ebro.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65673700, -0.87821900, '0101000020E6100000F33977BB5E1AECBF5D8940F50FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49465471091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49465471091.webp', 'https://www.flickr.com/photos/zaragozaantigua/49465471091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22091, 'Santiago Ap├│stol c.1950', 'Estatua del Ap├│stol Santiago, obra del escultor Antonio Torres, en el taller de la calle de Florencio Jardiel, antes de ser colocada sobre la puerta Este de la bas├¡lica del Pilar de Zaragoza. La obra de remodelaci├│n de la fachada, dirigida por Teodoro R├¡os, fue inaugurada en 1952. Fuente visual: Im├ígenes de nuestras vidas. El Peri├│dico de Arag├│n, 2015.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65709700, -0.87951800, '0101000020E610000058C9C7EE0225ECBF5DA626C11BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19154405196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19154405196.webp', 'https://www.flickr.com/photos/zaragozaantigua/19154405196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22485, 'El Pilar 1964', 'Vista a├®rea del Pilar y el Ebro desde el oeste. Fuente: Foto TAF. Revista Triunfo.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65761600, -0.87854100, '0101000020E61000008E3EE603021DECBFC5A9D6C22CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40252493393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40252493393.webp', 'https://www.flickr.com/photos/zaragozaantigua/40252493393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21352, 'Plaza del Pilar c.1900', 'Imagen capturada en la plaza del Pilar y centrada en el concurrido ingreso bajo o principal al templo metropolitano. En primer t├®rmino, el empedrado pavimento del plaza lindero con la calle de Dami├ín Forment.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65597400, -0.87821900, '0101000020E6100000F33977BB5E1AECBF5E83BEF4F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54636251689.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54636251689.webp', 'https://www.flickr.com/photos/zaragozaantigua/54636251689/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23285, 'Calle de Alfonso I 1891', 'La calle Alfonso, una de esas tradicionales y castizas calles de las de "toda la vida", fue abierta en la d├®cada de 1860, como otra imitaci├│n del Par├¡s del Segundo Imperio. Su prop├│sito era crear un marco esc├®nico ideal para la burgues├¡a de la ciudad, uniendo el Coso con la plaza del Pilar. Su apertura se hizo modificando y realineando el trazado de todas las calles previas, comenzando por la calle del antiguo Trenque del Arzobispo, y terminando con la calle del antiguo Mes├│n de los Navarros. Como suele ser habitual, comerciantes e inquilinos protestaron porque las obras significaban el fin del mundo y el colapso de la econom├¡a internacional (por este orden). Todas las calles transversales debieron acomodar en chafl├ín su encuentro con la nueva v├¡a, y la homogeneidad compositiva se impuso en las fachadas de la calle, en cuyos bajos se instal├│ la crema comercial de la ciudad: caf├®s, confiter├¡as, bazares, plater├¡as, sastres. Alfonso I se convirti├│ en sin├│nimo de paseo, compras. escaparate, chafardeo, cotilleo. "Gan├│ la ciudad" es lo que se suele decir cuando en efecto son los propietarios del suelo y los bancos los que se llevan la parte del le├│n. En la imagen, visi├│n en altura de la nov├¡sima calle Alfonso I desde las alturas de la bas├¡lica concatedral, que permite apreciar en perspectiva la pulcra rectitud del nuevo trazado de esta parte antigua de la ciudad. Al fondo, en el entronque con el Coso Alto, ins├│lita vista del palacio del marqu├®s de Campo Franco, entre el palacio de S├ístago (izquierda) y el palacio del conde Fuentes (derecha), antes de ser convertida en la sede del Banco de Arag├│n (inaugurado en 1917). Mucho m├ís al fondo, el nuevo y descomunal edificio de la Facultad de Medicina y Ciencias, que se inaugurar├í un par de a├▒os despu├®s. Y m├ís all├í no hay m├ís. Fuente visual: AHPZ, Estudio Coyne, c.1891', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65597700, -0.87920600, '0101000020E6100000A14D0E9F7422ECBFCFF6E80DF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14984794535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14984794535.webp', 'https://www.flickr.com/photos/zaragozaantigua/14984794535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23809, 'Plaza del Pilar 1930', '"Entrada principal al templo de Nuestra Se├▒ora del Pilar". En la imagen, la "Puerta Baja", y aspecto parcial de la plaza del Pilar.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65629500, -0.87824000, '0101000020E6100000D13FC1C58A1AECBFA0C37C7901D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15421894968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15421894968.webp', 'https://www.flickr.com/photos/zaragozaantigua/15421894968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24888, 'Pl. del Pilar 1949', 'AHPZ. Estudio Coyne. "Obras del actual Ayuntamiento. Plaza de Nuestra Se├▒ora del Pilar. Remodelaci├│n de la fachada de la Catedral Bas├¡lica de Nuestra Se├▒ora del Pilar".', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65608000, -0.87787600, '0101000020E61000007B2FBE688F17ECBFA4C7EF6DFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15021790335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15021790335.webp', 'https://www.flickr.com/photos/zaragozaantigua/15021790335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21915, 'Pasaje del Comercio c.1935', 'Imagen capturada en el claroscuro interior del Pasaje del Comercio, construido en 1882-1883 a instancias del marqu├®s de Ayerbe, propietario del nuevo inmueble que ocupaba toda esa manzana. Al fondo contrasta la luminosa entrada desde la plaza del Pilar, donde destacan sus jardines y uno de los quioscos que flanqueaban el ingreso a la Puerta Baja del templo.', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST├ôRICO', 41.65588700, -0.87874500, '0101000020E6100000ADC090D5AD1EECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53206126035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53206126035.webp', 'https://www.flickr.com/photos/zaragozaantigua/53206126035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22704, 'Pl. del Pilar 1970', 'Zona oriental de la plaza del Pilar, en una vista capturada junto a la puerta Baja de la bas├¡lica y con el tel├│n de fondo de la plaza de la Seo. Los elementos decorativos, adem├ís de un ajardinado espacio al pie del monumento a Goya, conforman uno de los cambiantes montajes que han caracterizado este singular escenario urbano. A la derecha y en primer t├®rmino, mozos de reemplazo del antiguo Servicio Militar Obligatorio se dirigen al Pilar.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65584400, -0.87769600, '0101000020E61000007E8FFAEB1516ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27709802468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27709802468.webp', 'https://www.flickr.com/photos/zaragozaantigua/27709802468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23789, 'Calle del Pilar a├▒os 30', 'Calle del Pilar en los a├▒os 30, tras el derribo de la manzana que confrontaba con los inmuebles del lado de los impares. Fuente: Instant├íneas zaragozanas, 1982.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65590500, -0.87756400, '0101000020E6100000C4B304190115ECBF3524EEB1F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701157377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701157377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701157377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23893, 'Plaza del Pilar 1988', 'Actuaci├│n de Jos├® Antonio Labordeta en la plaza del Pilar en 1988. Al fondo, edificio El Cicl├│n, bas├¡lica y templete de turismo. Fuente: Heraldo de Arag├│n.', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65547300, -0.87811100, '0101000020E61000005B40683D7C19ECBF9C340D8AE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33741166695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33741166695.webp', 'https://www.flickr.com/photos/zaragozaantigua/33741166695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24873, 'Ayuntamiento c.1976', 'Edificio del Ayuntamiento, inaugurado en 1965 tras dos d├®cadas en construcci├│n, seg├║n proyecto de Alberto Acha, Mariano Nasarre y Ricardo Magdalena, en una escena nocturna. Adem├ís de la decoraci├│n encargada a Joaqu├¡n Herrero Pascual, lucen en la imagen, como ornato a├▒adido y en primer t├®rmino, decenas de veh├¡culos a motor aparcados en la plaza de la Independencia junto al Gobierno Civil, un ejemplo de su preponderancia en esta ├®poca.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST├ôRICO', 41.65588700, -0.87744500, '0101000020E6100000323D61890714ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725416809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725416809.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725416809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20969, 'Puerta de Toledo 1853', 'Xilograf├¡a, firmada por J.A. - Benedicto, del arco o puerta de Toledo. Ya hab├¡a sido derribada en 1842. Est├í basada en un dibujo a l├ípiz de Cecilio Pizarro y Librado. Fuente: Semanario Pintoresco Espa├▒ol, 1853.', 1853, 1853, 1853, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19070326531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19070326531.webp', 'https://www.flickr.com/photos/zaragozaantigua/19070326531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
